    "code": "<span class='highlight comment'># Definition <span class='highlight keyword'>for</span> singly<span class='highlight bracket'>-</span>linked list.</span>\n<span class='highlight comment'># <span class='highlight keyword'>class</span> ListNode<span class='highlight bracket'>(</span><span class='highlight buildin-type'>object</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span></span>\n<span class='highlight comment'>#     <span class='highlight keyword'>def</span> __init__<span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> x<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span></span>\n<span class='highlight comment'>#         <span class='highlight buildin-type'>self</span>.val <span class='highlight bracket'>=</span> x</span>\n<span class='highlight comment'>#         <span class='highlight buildin-type'>self</span>.next <span class='highlight bracket'>=</span> <span class='highlight buildin-type'>None</span></span>\n\n<span class='highlight keyword'>class</span> Solution<span class='highlight bracket'>(</span><span class='highlight buildin-type'>object</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n    <span class='highlight keyword'>def</span> <span class='highlight object'>swapPairs</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> head<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        dummy_head <span class='highlight bracket'>=</span> ListNode<span class='highlight bracket'>(</span><span class='highlight string'>'dummy'</span><span class='highlight bracket'>)</span>\n        dummy_head.next <span class='highlight bracket'>=</span> head\n        cur <span class='highlight bracket'>=</span> dummy_head\n        <span class='highlight keyword'>while</span> cur <span class='highlight keyword'>and</span> cur.next <span class='highlight keyword'>and</span> cur.next.next<span class='highlight bracket'>:</span>\n            nodes <span class='highlight bracket'>=</span> <span class='highlight bracket'>[</span>cur<span class='highlight bracket'>,</span> cur.next<span class='highlight bracket'>,</span> cur.next.next<span class='highlight bracket'>,</span> cur.next.next.next<span class='highlight bracket'>]</span>\n            nodes<span class='highlight bracket'>[</span>0<span class='highlight bracket'>]</span>.next<span class='highlight bracket'>,</span> nodes<span class='highlight bracket'>[</span>1<span class='highlight bracket'>]</span>.next<span class='highlight bracket'>,</span> nodes<span class='highlight bracket'>[</span>2<span class='highlight bracket'>]</span>.next<span class='highlight bracket'>,</span> cur <span class='highlight bracket'>=</span> nodes<span class='highlight bracket'>[</span>2<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> nodes<span class='highlight bracket'>[</span>3<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> nodes<span class='highlight bracket'>[</span>1<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> nodes<span class='highlight bracket'>[</span>1<span class='highlight bracket'>]</span>\n        <span class='highlight keyword'>return</span> dummy_head.next",
