    "code": "<span class='highlight keyword'>class</span> Solution<span class='highlight bracket'>(</span><span class='highlight buildin-type'>object</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n    <span class='highlight keyword'>def</span> <span class='highlight object'>trap</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> height<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        <span class='highlight keyword'>if</span> <span class='highlight keyword'>not</span> height<span class='highlight bracket'>:</span> <span class='highlight keyword'>return</span> 0\n        l<span class='highlight bracket'>,</span> r <span class='highlight bracket'>=</span> 0<span class='highlight bracket'>,</span> <span class='highlight buildin-function'>len</span><span class='highlight bracket'>(</span>height<span class='highlight bracket'>)</span> <span class='highlight bracket'>-</span> 1\n        res <span class='highlight bracket'>=</span> 0\n        l_max<span class='highlight bracket'>,</span>  r_max <span class='highlight bracket'>=</span> height<span class='highlight bracket'>[</span>l<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> height<span class='highlight bracket'>[</span>r<span class='highlight bracket'>]</span>\n        <span class='highlight keyword'>while</span> l <span class='highlight bracket'><=</span> r<span class='highlight bracket'>:</span>\n            lh<span class='highlight bracket'>,</span> rh <span class='highlight bracket'>=</span> height<span class='highlight bracket'>[</span>l<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> height<span class='highlight bracket'>[</span>r<span class='highlight bracket'>]</span>\n            <span class='highlight keyword'>if</span> l_max <span class='highlight bracket'><</span> r_max<span class='highlight bracket'>:</span>\n                res <span class='highlight bracket'>+</span><span class='highlight bracket'>=</span> <span class='highlight buildin-function'>max</span><span class='highlight bracket'>(</span><span class='highlight buildin-function'>min</span><span class='highlight bracket'>(</span>r_max<span class='highlight bracket'>,</span> l_max<span class='highlight bracket'>)</span> <span class='highlight bracket'>-</span> lh<span class='highlight bracket'>,</span> 0<span class='highlight bracket'>)</span>\n                l <span class='highlight bracket'>+</span><span class='highlight bracket'>=</span> 1\n                l_max <span class='highlight bracket'>=</span> <span class='highlight buildin-function'>max</span><span class='highlight bracket'>(</span>l_max<span class='highlight bracket'>,</span> lh<span class='highlight bracket'>)</span>\n            <span class='highlight keyword'>else</span><span class='highlight bracket'>:</span>\n                res <span class='highlight bracket'>+</span><span class='highlight bracket'>=</span> <span class='highlight buildin-function'>max</span><span class='highlight bracket'>(</span><span class='highlight buildin-function'>min</span><span class='highlight bracket'>(</span>l_max<span class='highlight bracket'>,</span> r_max<span class='highlight bracket'>)</span> <span class='highlight bracket'>-</span> rh<span class='highlight bracket'>,</span> 0<span class='highlight bracket'>)</span>\n                r <span class='highlight bracket'>-</span><span class='highlight bracket'>=</span> 1\n                r_max <span class='highlight bracket'>=</span> <span class='highlight buildin-function'>max</span><span class='highlight bracket'>(</span>r_max<span class='highlight bracket'>,</span> rh<span class='highlight bracket'>)</span>\n            <span class='highlight keyword'>print</span> <span class='highlight bracket'>(</span>l<span class='highlight bracket'>,</span>lh<span class='highlight bracket'>)</span><span class='highlight bracket'>,</span> <span class='highlight bracket'>(</span>r<span class='highlight bracket'>,</span>rh<span class='highlight bracket'>)</span><span class='highlight bracket'>,</span> res\n        <span class='highlight keyword'>return</span> res\n                ",
