    "code": "<span class='highlight keyword'>class</span> Solution<span class='highlight bracket'>(</span><span class='highlight buildin-type'>object</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n    <span class='highlight keyword'>def</span> <span class='highlight object'>rotate</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> matrix<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        <span class='highlight keyword'>for</span> i <span class='highlight keyword'>in</span> <span class='highlight buildin-function'>range</span><span class='highlight bracket'>(</span><span class='highlight buildin-function'>len</span><span class='highlight bracket'>(</span>matrix<span class='highlight bracket'>)</span> <span class='highlight bracket'>/</span> 2<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n            <span class='highlight keyword'>for</span> j <span class='highlight keyword'>in</span> <span class='highlight buildin-function'>range</span><span class='highlight bracket'>(</span>i<span class='highlight bracket'>,</span> <span class='highlight buildin-function'>len</span><span class='highlight bracket'>(</span>matrix<span class='highlight bracket'>)</span> <span class='highlight bracket'>-</span> i <span class='highlight bracket'>-</span> 1<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n                n <span class='highlight bracket'>=</span> <span class='highlight buildin-function'>len</span><span class='highlight bracket'>(</span>matrix<span class='highlight bracket'>)</span> <span class='highlight bracket'>-</span> 1\n                vals <span class='highlight bracket'>=</span> matrix<span class='highlight bracket'>[</span>i<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>j<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> matrix<span class='highlight bracket'>[</span>j<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>n <span class='highlight bracket'>-</span> i<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> matrix<span class='highlight bracket'>[</span>n <span class='highlight bracket'>-</span> i<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>n <span class='highlight bracket'>-</span> j<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> matrix<span class='highlight bracket'>[</span>n <span class='highlight bracket'>-</span> j<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>i<span class='highlight bracket'>]</span>\n                matrix<span class='highlight bracket'>[</span>i<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>j<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> matrix<span class='highlight bracket'>[</span>j<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>n <span class='highlight bracket'>-</span> i<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> matrix<span class='highlight bracket'>[</span>n <span class='highlight bracket'>-</span> i<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>n <span class='highlight bracket'>-</span> j<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> matrix<span class='highlight bracket'>[</span>n <span class='highlight bracket'>-</span> j<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>i<span class='highlight bracket'>]</span> <span class='highlight bracket'>=</span> vals<span class='highlight bracket'>[</span>3<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> vals<span class='highlight bracket'>[</span>0<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> vals<span class='highlight bracket'>[</span>1<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> vals<span class='highlight bracket'>[</span>2<span class='highlight bracket'>]</span>",
