    "code": "<span class='highlight comment'># Definition <span class='highlight keyword'>for</span> an interval.</span>\n<span class='highlight comment'># <span class='highlight keyword'>class</span> Interval<span class='highlight bracket'>(</span><span class='highlight buildin-type'>object</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span></span>\n<span class='highlight comment'>#     <span class='highlight keyword'>def</span> __init__<span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> s<span class='highlight bracket'>=</span>0<span class='highlight bracket'>,</span> e<span class='highlight bracket'>=</span>0<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span></span>\n<span class='highlight comment'>#         <span class='highlight buildin-type'>self</span>.start <span class='highlight bracket'>=</span> s</span>\n<span class='highlight comment'>#         <span class='highlight buildin-type'>self</span>.end <span class='highlight bracket'>=</span> e</span>\n\n<span class='highlight keyword'>class</span> Solution<span class='highlight bracket'>(</span><span class='highlight buildin-type'>object</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n    <span class='highlight keyword'>def</span> <span class='highlight object'>insert</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> intervals<span class='highlight bracket'>,</span> newInterval<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        left<span class='highlight bracket'>,</span> right <span class='highlight bracket'>=</span> <span class='highlight bracket'>[</span><span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> <span class='highlight bracket'>[</span><span class='highlight bracket'>]</span>\n        s<span class='highlight bracket'>,</span> e <span class='highlight bracket'>=</span> newInterval.start<span class='highlight bracket'>,</span> newInterval.end\n        <span class='highlight keyword'>for</span> interval <span class='highlight keyword'>in</span> intervals<span class='highlight bracket'>:</span>\n            <span class='highlight keyword'>if</span> interval.end <span class='highlight bracket'><</span> s<span class='highlight bracket'>:</span> left.<span class='highlight object'>append</span><span class='highlight bracket'>(</span>interval<span class='highlight bracket'>)</span>\n            <span class='highlight keyword'>elif</span> e <span class='highlight bracket'><</span> interval.start<span class='highlight bracket'>:</span> right.<span class='highlight object'>append</span><span class='highlight bracket'>(</span>interval<span class='highlight bracket'>)</span>\n            <span class='highlight keyword'>else</span><span class='highlight bracket'>:</span> s<span class='highlight bracket'>,</span> e <span class='highlight bracket'>=</span> <span class='highlight buildin-function'>min</span><span class='highlight bracket'>(</span>interval.start<span class='highlight bracket'>,</span> s<span class='highlight bracket'>)</span><span class='highlight bracket'>,</span> <span class='highlight buildin-function'>max</span><span class='highlight bracket'>(</span>interval.end<span class='highlight bracket'>,</span> e<span class='highlight bracket'>)</span>\n        <span class='highlight keyword'>return</span> left <span class='highlight bracket'>+</span> <span class='highlight bracket'>[</span>Interval<span class='highlight bracket'>(</span>s<span class='highlight bracket'>,</span> e<span class='highlight bracket'>)</span><span class='highlight bracket'>]</span> <span class='highlight bracket'>+</span> right\n        ",
