    "code": "<span class='highlight keyword'>class</span> Solution<span class='highlight bracket'>(</span><span class='highlight buildin-type'>object</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n    <span class='highlight keyword'>def</span> <span class='highlight object'>exist</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> board<span class='highlight bracket'>,</span> word<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        m<span class='highlight bracket'>,</span> n <span class='highlight bracket'>=</span> <span class='highlight buildin-function'>len</span><span class='highlight bracket'>(</span>board<span class='highlight bracket'>)</span><span class='highlight bracket'>,</span> <span class='highlight buildin-function'>len</span><span class='highlight bracket'>(</span>board<span class='highlight bracket'>[</span>0<span class='highlight bracket'>]</span><span class='highlight bracket'>)</span>\n        visited <span class='highlight bracket'>=</span> <span class='highlight bracket'>[</span><span class='highlight bracket'>[</span><span class='highlight buildin-type'>False</span><span class='highlight bracket'>]</span> <span class='highlight bracket'>*</span> n <span class='highlight keyword'>for</span> _ <span class='highlight keyword'>in</span> <span class='highlight buildin-function'>range</span><span class='highlight bracket'>(</span>m<span class='highlight bracket'>)</span><span class='highlight bracket'>]</span>\n        <span class='highlight keyword'>def</span> <span class='highlight object'>exist</span><span class='highlight bracket'>(</span>i<span class='highlight bracket'>,</span> j<span class='highlight bracket'>,</span> char_i<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n            <span class='highlight keyword'>if</span> word<span class='highlight bracket'>[</span>char_i<span class='highlight bracket'>]</span> <span class='highlight bracket'>!</span><span class='highlight bracket'>=</span> board<span class='highlight bracket'>[</span>i<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>j<span class='highlight bracket'>]</span><span class='highlight bracket'>:</span> <span class='highlight keyword'>return</span> <span class='highlight buildin-type'>False</span>\n            <span class='highlight keyword'>elif</span> char_i <span class='highlight bracket'>==</span> <span class='highlight buildin-function'>len</span><span class='highlight bracket'>(</span>word<span class='highlight bracket'>)</span> <span class='highlight bracket'>-</span> 1 <span class='highlight keyword'>and</span> <span class='highlight keyword'>not</span> visited<span class='highlight bracket'>[</span>i<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>j<span class='highlight bracket'>]</span><span class='highlight bracket'>:</span> <span class='highlight keyword'>return</span> <span class='highlight buildin-type'>True</span>\n            adjs <span class='highlight bracket'>=</span> <span class='highlight bracket'>[</span><span class='highlight bracket'>(</span>i <span class='highlight bracket'>+</span> a<span class='highlight bracket'>,</span> j <span class='highlight bracket'>+</span> b<span class='highlight bracket'>)</span>\n                    <span class='highlight keyword'>for</span> a<span class='highlight bracket'>,</span> b <span class='highlight keyword'>in</span> <span class='highlight buildin-function'>zip</span><span class='highlight bracket'>(</span><span class='highlight bracket'>[</span>1<span class='highlight bracket'>,</span>0<span class='highlight bracket'>,</span><span class='highlight bracket'>-</span>1<span class='highlight bracket'>,</span>0<span class='highlight bracket'>]</span><span class='highlight bracket'>,</span> <span class='highlight bracket'>[</span>0<span class='highlight bracket'>,</span>1<span class='highlight bracket'>,</span>0<span class='highlight bracket'>,</span><span class='highlight bracket'>-</span>1<span class='highlight bracket'>]</span><span class='highlight bracket'>)</span>\n                    <span class='highlight keyword'>if</span> <span class='highlight bracket'>(</span>0 <span class='highlight bracket'><=</span> i <span class='highlight bracket'>+</span> a <span class='highlight bracket'><</span> m<span class='highlight bracket'>)</span> <span class='highlight keyword'>and</span> <span class='highlight bracket'>(</span>0 <span class='highlight bracket'><=</span> j <span class='highlight bracket'>+</span> b <span class='highlight bracket'><</span> n<span class='highlight bracket'>)</span><span class='highlight bracket'>]</span>\n            visited<span class='highlight bracket'>[</span>i<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>j<span class='highlight bracket'>]</span> <span class='highlight bracket'>=</span> <span class='highlight buildin-type'>True</span>\n            <span class='highlight keyword'>if</span> <span class='highlight buildin-function'>any</span><span class='highlight bracket'>(</span><span class='highlight keyword'>not</span> visited<span class='highlight bracket'>[</span>x<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>y<span class='highlight bracket'>]</span> <span class='highlight keyword'>and</span> <span class='highlight object'>exist</span><span class='highlight bracket'>(</span>x<span class='highlight bracket'>,</span> y<span class='highlight bracket'>,</span> char_i <span class='highlight bracket'>+</span> 1<span class='highlight bracket'>)</span>\n                   <span class='highlight keyword'>for</span> x<span class='highlight bracket'>,</span> y <span class='highlight keyword'>in</span> adjs<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n                    <span class='highlight keyword'>return</span> <span class='highlight buildin-type'>True</span>\n            visited<span class='highlight bracket'>[</span>i<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>j<span class='highlight bracket'>]</span> <span class='highlight bracket'>=</span> <span class='highlight buildin-type'>False</span>\n            <span class='highlight keyword'>return</span> <span class='highlight buildin-type'>False</span>\n\n        <span class='highlight keyword'>return</span> <span class='highlight buildin-function'>any</span><span class='highlight bracket'>(</span><span class='highlight object'>exist</span><span class='highlight bracket'>(</span>i<span class='highlight bracket'>,</span> j<span class='highlight bracket'>,</span> 0<span class='highlight bracket'>)</span>\n                   <span class='highlight keyword'>for</span> i <span class='highlight keyword'>in</span> <span class='highlight buildin-function'>range</span><span class='highlight bracket'>(</span>m<span class='highlight bracket'>)</span>\n                   <span class='highlight keyword'>for</span> j <span class='highlight keyword'>in</span> <span class='highlight buildin-function'>range</span><span class='highlight bracket'>(</span>n<span class='highlight bracket'>)</span><span class='highlight bracket'>)</span>",
