    "code": "<span class='highlight keyword'>class</span> Solution<span class='highlight bracket'>(</span><span class='highlight buildin-type'>object</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n    <span class='highlight keyword'>def</span> <span class='highlight object'>largestRectangleArea</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> heights<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        heights.<span class='highlight object'>append</span><span class='highlight bracket'>(</span>0<span class='highlight bracket'>)</span>\n        dp <span class='highlight bracket'>=</span> <span class='highlight bracket'>[</span><span class='highlight bracket'>]</span>\n        max_area <span class='highlight bracket'>=</span> 0\n        <span class='highlight keyword'>for</span> i<span class='highlight bracket'>,</span> height <span class='highlight keyword'>in</span> <span class='highlight buildin-function'>enumerate</span><span class='highlight bracket'>(</span>heights<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n            left <span class='highlight bracket'>=</span> i\n            <span class='highlight keyword'>while</span> dp <span class='highlight keyword'>and</span> dp<span class='highlight bracket'>[</span><span class='highlight bracket'>-</span>1<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>1<span class='highlight bracket'>]</span> <span class='highlight bracket'>></span> height<span class='highlight bracket'>:</span>\n                left <span class='highlight bracket'>=</span> dp<span class='highlight bracket'>[</span><span class='highlight bracket'>-</span>1<span class='highlight bracket'>]</span><span class='highlight bracket'>[</span>0<span class='highlight bracket'>]</span>\n                j<span class='highlight bracket'>,</span> j_height <span class='highlight bracket'>=</span> dp.<span class='highlight object'>pop</span><span class='highlight bracket'>(</span><span class='highlight bracket'>)</span>\n                max_area <span class='highlight bracket'>=</span> <span class='highlight buildin-function'>max</span><span class='highlight bracket'>(</span>max_area<span class='highlight bracket'>,</span> j_height <span class='highlight bracket'>*</span> <span class='highlight bracket'>(</span>i <span class='highlight bracket'>-</span> j<span class='highlight bracket'>)</span><span class='highlight bracket'>)</span>\n            dp.<span class='highlight object'>append</span><span class='highlight bracket'>(</span><span class='highlight bracket'>(</span>left<span class='highlight bracket'>,</span> height<span class='highlight bracket'>)</span><span class='highlight bracket'>)</span>\n        <span class='highlight keyword'>return</span> max_area",
