    "code": "<span class='highlight comment'># Definition <span class='highlight keyword'>for</span> a binary tree node.</span>\n<span class='highlight comment'># <span class='highlight keyword'>class</span> TreeNode<span class='highlight bracket'>(</span><span class='highlight buildin-type'>object</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span></span>\n<span class='highlight comment'>#     <span class='highlight keyword'>def</span> __init__<span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> x<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span></span>\n<span class='highlight comment'>#         <span class='highlight buildin-type'>self</span>.val <span class='highlight bracket'>=</span> x</span>\n<span class='highlight comment'>#         <span class='highlight buildin-type'>self</span>.left <span class='highlight bracket'>=</span> <span class='highlight buildin-type'>None</span></span>\n<span class='highlight comment'>#         <span class='highlight buildin-type'>self</span>.right <span class='highlight bracket'>=</span> <span class='highlight buildin-type'>None</span></span>\n\n<span class='highlight keyword'>class</span> Solution<span class='highlight bracket'>(</span><span class='highlight buildin-type'>object</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n    <span class='highlight keyword'>def</span> <span class='highlight object'>maxPathSum</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> root<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        \n        <span class='highlight buildin-type'>self</span>.max_sum <span class='highlight bracket'>=</span> <span class='highlight buildin-function'>float</span><span class='highlight bracket'>(</span><span class='highlight string'>'<span class='highlight bracket'>-</span>inf'</span><span class='highlight bracket'>)</span>\n\n        <span class='highlight keyword'>def</span> _getmax<span class='highlight bracket'>(</span>node<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n            <span class='highlight keyword'>if</span> <span class='highlight keyword'>not</span> node<span class='highlight bracket'>:</span> <span class='highlight keyword'>return</span> 0\n            l<span class='highlight bracket'>,</span> r <span class='highlight bracket'>=</span> _getmax<span class='highlight bracket'>(</span>node.left<span class='highlight bracket'>)</span><span class='highlight bracket'>,</span> _getmax<span class='highlight bracket'>(</span>node.right<span class='highlight bracket'>)</span>\n            <span class='highlight buildin-type'>self</span>.max_sum <span class='highlight bracket'>=</span> <span class='highlight buildin-function'>max</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span>.max_sum<span class='highlight bracket'>,</span> l <span class='highlight bracket'>+</span> r <span class='highlight bracket'>+</span> node.val<span class='highlight bracket'>)</span>\n            <span class='highlight keyword'>return</span> <span class='highlight buildin-function'>max</span><span class='highlight bracket'>(</span><span class='highlight buildin-function'>max</span><span class='highlight bracket'>(</span>l<span class='highlight bracket'>,</span> r<span class='highlight bracket'>)</span> <span class='highlight bracket'>+</span> node.val<span class='highlight bracket'>,</span> 0<span class='highlight bracket'>)</span>\n        \n        _getmax<span class='highlight bracket'>(</span>root<span class='highlight bracket'>)</span>\n        <span class='highlight keyword'>return</span> <span class='highlight buildin-type'>self</span>.max_sum",
