    "companies": [
      "Amazon",
      "Google",
      "Microsoft",
      "eBay",
      "Walmart Labs",
      "Square"
    ],
    "code": "<span class='highlight keyword'>class</span> Trie<span class='highlight bracket'>(</span><span class='highlight buildin-type'>object</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n\n    <span class='highlight keyword'>def</span> __init__<span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        <span class='highlight buildin-type'>self</span>.trie_tree <span class='highlight bracket'>=</span> <span class='highlight bracket'>{</span><span class='highlight bracket'>}</span>\n\n    <span class='highlight keyword'>def</span> <span class='highlight object'>insert</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> word<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        cur <span class='highlight bracket'>=</span> <span class='highlight buildin-type'>self</span>.trie_tree\n        <span class='highlight keyword'>for</span> char <span class='highlight keyword'>in</span> word<span class='highlight bracket'>:</span> cur <span class='highlight bracket'>=</span> cur.<span class='highlight object'>setdefault</span><span class='highlight bracket'>(</span>char<span class='highlight bracket'>,</span> <span class='highlight bracket'>{</span><span class='highlight bracket'>}</span><span class='highlight bracket'>)</span>\n        cur<span class='highlight bracket'>[</span><span class='highlight buildin-type'>True</span><span class='highlight bracket'>]</span> <span class='highlight bracket'>=</span> <span class='highlight buildin-type'>True</span>\n\n    <span class='highlight keyword'>def</span> <span class='highlight object'>search</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> word<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        cur <span class='highlight bracket'>=</span> <span class='highlight buildin-type'>self</span>.trie_tree\n        <span class='highlight keyword'>for</span> char <span class='highlight keyword'>in</span> word<span class='highlight bracket'>:</span> \n            <span class='highlight keyword'>if</span> char <span class='highlight keyword'>not</span> <span class='highlight keyword'>in</span> cur<span class='highlight bracket'>:</span> <span class='highlight keyword'>return</span> <span class='highlight buildin-type'>False</span>\n            cur <span class='highlight bracket'>=</span> cur<span class='highlight bracket'>[</span>char<span class='highlight bracket'>]</span>\n        <span class='highlight keyword'>return</span> <span class='highlight buildin-type'>True</span> <span class='highlight keyword'>in</span> cur\n        \n\n    <span class='highlight keyword'>def</span> <span class='highlight object'>startsWith</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> prefix<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        cur <span class='highlight bracket'>=</span> <span class='highlight buildin-type'>self</span>.trie_tree\n        <span class='highlight keyword'>for</span> char <span class='highlight keyword'>in</span> prefix<span class='highlight bracket'>:</span>\n            <span class='highlight keyword'>if</span> char <span class='highlight keyword'>not</span> <span class='highlight keyword'>in</span> cur<span class='highlight bracket'>:</span> <span class='highlight keyword'>return</span> <span class='highlight buildin-type'>False</span>\n            cur <span class='highlight bracket'>=</span> cur<span class='highlight bracket'>[</span>char<span class='highlight bracket'>]</span>\n        <span class='highlight keyword'>return</span> <span class='highlight buildin-type'>True</span>\n\n\n<span class='highlight comment'># Your Trie <span class='highlight buildin-type'>object</span> will be instantiated <span class='highlight keyword'>and</span> called <span class='highlight keyword'>as</span> such<span class='highlight bracket'>:</span></span>\n<span class='highlight comment'># obj <span class='highlight bracket'>=</span> Trie<span class='highlight bracket'>(</span><span class='highlight bracket'>)</span></span>\n<span class='highlight comment'># obj.<span class='highlight object'>insert</span><span class='highlight bracket'>(</span>word<span class='highlight bracket'>)</span></span>\n<span class='highlight comment'># param_2 <span class='highlight bracket'>=</span> obj.<span class='highlight object'>search</span><span class='highlight bracket'>(</span>word<span class='highlight bracket'>)</span></span>\n<span class='highlight comment'># param_3 <span class='highlight bracket'>=</span> obj.<span class='highlight object'>startsWith</span><span class='highlight bracket'>(</span>prefix<span class='highlight bracket'>)</span></span>",
