    "code": "<span class='highlight keyword'>class</span> WordDictionary<span class='highlight bracket'>(</span><span class='highlight buildin-type'>object</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n\n    <span class='highlight keyword'>def</span> __init__<span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        <span class='highlight buildin-type'>self</span>.trie_tree <span class='highlight bracket'>=</span> <span class='highlight bracket'>{</span><span class='highlight bracket'>}</span>\n\n    <span class='highlight keyword'>def</span> <span class='highlight object'>addWord</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> word<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        cur <span class='highlight bracket'>=</span> <span class='highlight buildin-type'>self</span>.trie_tree\n        <span class='highlight keyword'>for</span> char <span class='highlight keyword'>in</span> word<span class='highlight bracket'>:</span>\n            cur <span class='highlight bracket'>=</span> cur.<span class='highlight object'>setdefault</span><span class='highlight bracket'>(</span>char<span class='highlight bracket'>,</span> <span class='highlight bracket'>{</span><span class='highlight bracket'>}</span><span class='highlight bracket'>)</span>\n        cur<span class='highlight bracket'>[</span><span class='highlight buildin-type'>True</span><span class='highlight bracket'>]</span> <span class='highlight bracket'>=</span> word\n\n    <span class='highlight keyword'>def</span> <span class='highlight object'>search</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> word<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        stack <span class='highlight bracket'>=</span> <span class='highlight bracket'>[</span><span class='highlight buildin-type'>self</span>.trie_tree<span class='highlight bracket'>]</span>\n        <span class='highlight keyword'>for</span> char <span class='highlight keyword'>in</span> word<span class='highlight bracket'>:</span>\n            <span class='highlight keyword'>if</span> <span class='highlight keyword'>not</span> stack<span class='highlight bracket'>:</span> <span class='highlight keyword'>return</span> <span class='highlight buildin-type'>False</span>\n            <span class='highlight keyword'>if</span> char <span class='highlight bracket'>==</span> <span class='highlight string'>'.'</span><span class='highlight bracket'>:</span>\n                stack <span class='highlight bracket'>=</span> <span class='highlight bracket'>[</span>cur<span class='highlight bracket'>[</span>cur_char<span class='highlight bracket'>]</span> <span class='highlight keyword'>for</span> cur <span class='highlight keyword'>in</span> stack <span class='highlight keyword'>for</span> cur_char <span class='highlight keyword'>in</span> cur <span class='highlight keyword'>if</span> cur_char <span class='highlight bracket'>!</span><span class='highlight bracket'>=</span> <span class='highlight buildin-type'>True</span><span class='highlight bracket'>]</span>\n            <span class='highlight keyword'>else</span><span class='highlight bracket'>:</span>\n                stack <span class='highlight bracket'>=</span> <span class='highlight bracket'>[</span>cur<span class='highlight bracket'>[</span>char<span class='highlight bracket'>]</span> <span class='highlight keyword'>for</span> cur <span class='highlight keyword'>in</span> stack <span class='highlight keyword'>if</span> char <span class='highlight keyword'>in</span> cur<span class='highlight bracket'>]</span>\n        <span class='highlight keyword'>return</span> <span class='highlight buildin-function'>any</span><span class='highlight bracket'>(</span>cur<span class='highlight bracket'>[</span><span class='highlight buildin-type'>True</span><span class='highlight bracket'>]</span> <span class='highlight keyword'>for</span> cur <span class='highlight keyword'>in</span> stack <span class='highlight keyword'>if</span> <span class='highlight buildin-type'>True</span> <span class='highlight keyword'>in</span> cur<span class='highlight bracket'>)</span>\n\n\n<span class='highlight comment'># Your WordDictionary <span class='highlight buildin-type'>object</span> will be instantiated <span class='highlight keyword'>and</span> called <span class='highlight keyword'>as</span> such<span class='highlight bracket'>:</span></span>\n<span class='highlight comment'># obj <span class='highlight bracket'>=</span> WordDictionary<span class='highlight bracket'>(</span><span class='highlight bracket'>)</span></span>\n<span class='highlight comment'># obj.<span class='highlight object'>addWord</span><span class='highlight bracket'>(</span>word<span class='highlight bracket'>)</span></span>\n<span class='highlight comment'># param_2 <span class='highlight bracket'>=</span> obj.<span class='highlight object'>search</span><span class='highlight bracket'>(</span>word<span class='highlight bracket'>)</span></span>",
