    "code": "<span class='highlight keyword'>class</span> Solution<span class='highlight bracket'>(</span><span class='highlight buildin-type'>object</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n    <span class='highlight keyword'>def</span> <span class='highlight object'>singleNumber</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> nums<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        xord <span class='highlight bracket'>=</span> 0\n        <span class='highlight keyword'>for</span> num <span class='highlight keyword'>in</span> nums<span class='highlight bracket'>:</span>\n            xord <span class='highlight bracket'>^</span><span class='highlight bracket'>=</span> num\n\n        <span class='highlight keyword'>for</span> i <span class='highlight keyword'>in</span> <span class='highlight object'>xrange</span><span class='highlight bracket'>(</span>32<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n            <span class='highlight keyword'>if</span> <span class='highlight bracket'>(</span>1 <span class='highlight bracket'><<</span> i<span class='highlight bracket'>)</span> <span class='highlight bracket'>&</span> xord<span class='highlight bracket'>:</span>\n                num1 <span class='highlight bracket'>=</span> 0\n                num2 <span class='highlight bracket'>=</span> 0\n                <span class='highlight keyword'>for</span> num <span class='highlight keyword'>in</span> nums<span class='highlight bracket'>:</span>\n                    <span class='highlight keyword'>if</span> <span class='highlight bracket'>(</span>1 <span class='highlight bracket'><<</span> i<span class='highlight bracket'>)</span> <span class='highlight bracket'>&</span> num<span class='highlight bracket'>:</span>\n                        num1 <span class='highlight bracket'>^</span><span class='highlight bracket'>=</span> num\n                    <span class='highlight keyword'>else</span><span class='highlight bracket'>:</span>\n                        num2 <span class='highlight bracket'>^</span><span class='highlight bracket'>=</span> num\n                <span class='highlight keyword'>return</span> <span class='highlight bracket'>[</span>num1<span class='highlight bracket'>,</span> num2<span class='highlight bracket'>]</span>",
