    "code": "<span class='highlight keyword'>class</span> Solution<span class='highlight bracket'>(</span><span class='highlight buildin-type'>object</span><span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n    <span class='highlight keyword'>def</span> <span class='highlight object'>addStrings</span><span class='highlight bracket'>(</span><span class='highlight buildin-type'>self</span><span class='highlight bracket'>,</span> num1<span class='highlight bracket'>,</span> num2<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n        <span class='highlight keyword'>def</span> <span class='highlight object'>convert_to_int</span><span class='highlight bracket'>(</span>num<span class='highlight bracket'>)</span><span class='highlight bracket'>:</span>\n            res <span class='highlight bracket'>=</span> 0\n            <span class='highlight keyword'>for</span> digit <span class='highlight keyword'>in</span> num<span class='highlight bracket'>:</span>\n                res <span class='highlight bracket'>*</span><span class='highlight bracket'>=</span> 10\n                res <span class='highlight bracket'>+</span><span class='highlight bracket'>=</span> <span class='highlight buildin-function'>ord</span><span class='highlight bracket'>(</span>digit<span class='highlight bracket'>)</span> <span class='highlight bracket'>-</span> <span class='highlight buildin-function'>ord</span><span class='highlight bracket'>(</span><span class='highlight string'>'0'</span><span class='highlight bracket'>)</span>\n            <span class='highlight keyword'>return</span> res\n        <span class='highlight keyword'>print</span> <span class='highlight object'>convert_to_int</span><span class='highlight bracket'>(</span>num1<span class='highlight bracket'>)</span><span class='highlight bracket'>,</span> <span class='highlight object'>convert_to_int</span><span class='highlight bracket'>(</span>num2<span class='highlight bracket'>)</span>\n        <span class='highlight keyword'>return</span> <span class='highlight buildin-function'>str</span><span class='highlight bracket'>(</span><span class='highlight object'>convert_to_int</span><span class='highlight bracket'>(</span>num1<span class='highlight bracket'>)</span> <span class='highlight bracket'>+</span> <span class='highlight object'>convert_to_int</span><span class='highlight bracket'>(</span>num2<span class='highlight bracket'>)</span><span class='highlight bracket'>)</span>",
